      data: chart ? chart.values : [],
      borderColor: getColor(index),
      backgroundColor: getBackgroundColor(index),
      tension: LINE_STYLE.tension,
      fill: false,
      pointRadius: LINE_STYLE.pointRadius,
      pointHoverRadius: LINE_STYLE.pointHoverRadius,
